#include<bits/stdc++.h>
using namespace std;
struct node
{
    int lson,rson;
    int sum;
}t[6400010];
int tot,root[200010];
void add(int &x,int l,int r,int p,int v)
{
    if(r<p||l>p)
    {
        return;
    }
    if(x==0)
    {
        x=++tot;
    }
    if(l==r)
    {
        t[x].sum+=v;
        return;
    }
    int mid=(l+r)>>1;
    add(t[x].lson,l,mid,p,v);
    add(t[x].rson,mid+1,r,p,v);
    t[x].sum=t[t[x].lson].sum+t[t[x].rson].sum;
}
int query(int x,int l,int r,int u,int v)
{
    if(x==0||l>v||r<u)
    {
        return 0;
    }
    if(u<=l&&r<=v)
    {
        return t[x].sum;
    }
    int mid=(l+r)>>1;
    return query(t[x].lson,l,mid,u,v)+query(t[x].rson,mid+1,r,u,v);
}
int a[100010];
map<int,int> mp;
int main()
{
    int n,m,tot=0;
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        if(!mp[a[i]])
        {
            mp[a[i]]=++tot;
        }
        a[i]=mp[a[i]];
        add(root[a[i]],1,n,i,1);
    }
    while(m--)
    {
        char op;
        int x,y,v;
        cin>>op;
        scanf("%d%d",&x,&y);
        if(op=='C')
        {
            if(!mp[y])
            {
                mp[y]=++tot;
            }
            y=mp[y];
            add(root[a[x]],1,n,x,-1);
            a[x]=y;
            add(root[a[x]],1,n,x,1);
        }
        else
        {
            scanf("%d",&v);
            if(!mp[v])
            {
                printf("0\n");
                continue;
            }
            v=mp[v];
            printf("%d\n",query(root[v],1,n,x,y));
        }
    }
    return 0;
}
